INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316032, 'UTI-PRIORITARIO-MOT', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316033, 'UTI-PRIORITARIO-MOT', 'Nome?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316034, 'UTI-PRIORITARIO-MOT', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316035, 'UTI-PRIORITARIO-MOT', 'O operador confirmou a senha de segurança antes de prosseguir?', 'A verificação de senha protege a comunicação e evita repasses indevidos de informações. | Exemplo oficial: "Antes de prosseguirmos, poderia me confirmar sua senha de segurança, por favor?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316036, 'UTI-PRIORITARIO-MOT', 'O operador informou claramente o motivo do contato?', 'O motorista precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta detectado no sistema. Preciso verificar sua situação."', 1.03, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316037, 'UTI-PRIORITARIO-MOT', 'O operador confirmou a localização e a condição do motorista?', 'Ter a posição exata e saber se há risco permite uma melhor análise da ocorrência. | Exemplo oficial: "Pode me confirmar onde exatamente você está agora? Movimento ou parado?"', 1.7, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316038, 'UTI-PRIORITARIO-MOT', 'O operador identificou o motivo do alerta? (Sinistro, manutenção, problema técnico, acionamento indevido, etc.)', 'A causa do alerta precisa ser identificada rapidamente para tomada de decisão. | Exemplo oficial: "Consegue me informar o que ocorreu para esse alerta ter subido para mim?"', 1.92, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316039, 'UTI-PRIORITARIO-MOT', 'O operador solicitou vídeo do veículo nos casos necessários (Painel violado, Botão de pânico, Perda de Bateria, Teclado Desconectado, Sensor de desengate e baú)?', 'A solicitação do vídeo é essencial para análise mais detalhada e para garantir a segurança do motorista e da carga. | Exemplo oficial: "O senhor consegue enviar para nós um vídeo no WhatsApp? No vídeo precisa falar seu nome, senha de segurança, data e horário atuais”', 1.7, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316040, 'UTI-PRIORITARIO-MOT', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316041, 'UTI-PRIORITARIO-MOT', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316042, 'UTI-PRIORITARIO-MOT', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316043, 'UTI-PRIORITARIO-MOT', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: Exemplo: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Motorista/Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316044, 'UTI-PRIORITARIO-MOT', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316045, 'UTI-PRIORITARIO-MOT', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de gírias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316046, 'UTI-PRIORITARIO-CLI', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316047, 'UTI-PRIORITARIO-CLI', 'Nome?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316048, 'UTI-PRIORITARIO-CLI', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316049, 'UTI-PRIORITARIO-CLI', 'Confirmou com quem está falando?', 'Garante que a informação seja passada para a pessoa correta. | Exemplo oficial: "Por gentileza, com quem eu falo?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316050, 'UTI-PRIORITARIO-CLI', 'O operador informou claramente o motivo do contato?', 'O cliente precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta prioritário detectado no sistema. Preciso verificar a situação."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316051, 'UTI-PRIORITARIO-CLI', 'O operador enfatizou ao cliente que estava atuando em uma suspeita de sinistro?', 'Alerta o cliente sobre a gravidade da situação, reforçando a necessidade de atenção e suporte imediato. | Exemplo oficial: "Estamos tratando este caso como uma suspeita de sinistro e intensificando as tratativas para garantir a segurança da carga e do veículo."', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316052, 'UTI-PRIORITARIO-CLI', 'O operador informou as ações adotadas até o momento?', 'Garante que o cliente tenha clareza sobre as tratativas realizadas e próximos passos. | Exemplo oficial: "Já realizamos tentativas de contato com o motorista e ponto de apoio, além de enviar comandos ao rastreador, sem sucesso até o momento."', 1.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316053, 'UTI-PRIORITARIO-CLI', 'O operador informou corretamente o local onde gerou o alerta? (Cidade, estado, referência como rodovia, posto, mecânica, etc.)', 'Ajuda o cliente a entender o contexto e avaliar o risco da situação. | Exemplo oficial: "O veículo estava na cidade de [cidade], próximo ao [posto/mecânica/km da rodovia]."', 1.8, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316054, 'UTI-PRIORITARIO-CLI', 'O operador confirmou os contatos atuais do condutor?', 'Garante que os números utilizados estão corretos, evitando tentativas de contato desatualizadas. | Exemplo oficial: "O número de telefone que temos registrado para o condutor é [número]. Confirma se está correto ou há outro contato atualizado?"', 1.8, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
