INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316084, 'UTI-POSICAO-CLI', 'O operador questionou se o conjunto possui equipamento de contingência? (Ex.: isca, rastreador secundário, bloqueio remoto)', 'Identifica possíveis alternativas para recuperar a visibilidade do veículo. | Exemplo oficial: "Esse veículo possui algum equipamento de contingência, como segundo rastreador ou isca?"', 1.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316085, 'UTI-POSICAO-CLI', 'O operador questionou se o cliente tem informações recentes sobre o veículo e o motorista? (Ex.: manutenção, revisão, problemas no rastreador)', 'Permite cruzar informações, pois o motorista pode ter informado o cliente antes da gerenciadora. | Exemplo oficial: "O motorista mencionou recentemente alguma manutenção, revisão ou problemas no rastreador diretamente com vocês?"', 1.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
