INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316087, 'UTI-POSICAO-CLI', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316088, 'UTI-POSICAO-CLI', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316089, 'UTI-POSICAO-CLI', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316090, 'UTI-POSICAO-CLI', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: Exemplo: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316091, 'UTI-POSICAO-CLI', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316092, 'UTI-POSICAO-CLI', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de girias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316093, 'UTI-PARADA-MOT', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
