INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316112, 'UTI-PARADA-CLI', 'O operador informou claramente o motivo do contato?', 'O cliente precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta parada indevida detectado no sistema. Preciso verificar ua situação."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
