INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316162, 'UTI-PONTO-APOIO', 'O operador informou os dados e as características do veículo? (cor, placa, modelo)', 'Garante que a verificação seja feita no veículo correto. | Exemplo oficial: "O veículo que estamos monitorando é um [modelo] de cor [cor], placa [placa]."', 1.95, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316163, 'UTI-PONTO-APOIO', 'O operador passou detalhes da última posição do veículo? (Referência dentro do posto)', 'Confirma se o veículo realmente está no local indicado pelo sistema. | Exemplo oficial: "O sistema mostra que ele está na área de abastecimento do posto. Pode confirmar essa informação?"', 1.6, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316164, 'UTI-PONTO-APOIO', 'O operador solicitou que o atendente verificasse se o conjunto (cavalo/carreta) estava no local sem violações?', 'Certifica que não houve irregularidades ou violações durante a parada. | Exemplo oficial: "Pode verificar se o conjunto esta sem nenhuma violação?"', 1.6, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316165, 'UTI-PONTO-APOIO', 'O operador orientou o atendente a chamar o motorista?', 'Em alguns casos, falar diretamente com o motorista pode acelerar a verificação da situação. | Exemplo oficial: "Poderia solicitar que o motorista venha até o telefone para conversarmos?"', 1.6, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
