INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316177, 'UTI-PRIORITARIO-POLICIA', 'O operador informou os dados e as características do conjunto e do motorista? (cavalo, carreta, cor, modelo)', 'Garante que a abordagem seja feita no veículo correto. | Exemplo oficial: "Trata-se de um [modelo] de cor [cor], placa [placa], puxando uma carreta [tipo]."', 1.35, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316178, 'UTI-PRIORITARIO-POLICIA', 'O operador passou detalhes do local da ocorrência? (Rodovia, Referência, KM)', 'Ajuda a equipe policial a identificar com precisão a localização para uma resposta mais rápida. | Exemplo oficial: "O último posicionamento do veículo foi na BR-101, próximo ao KM 75, sentido sul."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316179, 'UTI-PRIORITARIO-POLICIA', 'O operador solicitou deslocamento e/ou reporte da ocorrência para patrulhamento?', 'Garante que a solicitação seja clara e direta, aumentando a chance de uma abordagem rápida. | Exemplo oficial: "Solicitamos apoio para patrulhamento e abordagem do veículo em situação suspeita."', 1.5, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316180, 'UTI-PRIORITARIO-POLICIA', 'O operador deixou telefone de contato para retorno?', 'Garante um canal de comunicação aberto para atualizações e suporte adicional. | Exemplo oficial: "Podem retornar para o número 0800 727 6101 Opção 3 para qualquer atualização."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316181, 'UTI-PRIORITARIO-POLICIA', 'O operador utilizou o alfabeto fonético ao passar informações?', 'Evita erros na transmissão de placas e códigos, garantindo clareza. | Exemplo oficial: "Placa do veículo: Alfa, Bravo, Charlie, primeiro, segundo, terceiro, quarto."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
