INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316187, 'UTI-PRIORITARIO-POLICIA', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de girias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316188, 'BAS-PRIORITARIO-POLICIA', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
