INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316411, 'LOGISTICA-ATIVACAO-AE', 'Confirmou com quem está falando?', 'Garante que a informação seja passada para a pessoa correta. | Exemplo oficial: "Por gentileza, estou falando com [Nome do Cliente/Responsável]?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316412, 'LOGISTICA-ATIVACAO-AE', 'Informou o motivo do contato?', 'O cliente deve ser informado claramente sobre a necessidade de ativação da AE. | Exemplo oficial: "Estou entrando em contato para solicitar a ativação da AE referente à programação X."', 1.95, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316413, 'LOGISTICA-ATIVACAO-AE', 'Informou nº da programação ou outra informação semelhante?', 'Fornecer a identificação correta da solicitação evita confusão e agiliza o atendimento. | Exemplo oficial: "O número da programação é 12345.''"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316414, 'LOGISTICA-ATIVACAO-AE', 'Se estiver atrasada, questionou o motivo do atraso na emissão?', 'Identificar a causa do atraso para adoção das melhores medidas. | Exemplo oficial: "Qual o motivo do atraso na emissão dessa viagem?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316415, 'LOGISTICA-ATIVACAO-AE', 'Solicitou emissão?', 'É essencial confirmar a solicitação da ativação para garantir que o processo seja iniciado corretamente. | Exemplo oficial: "Você pode por favor realizar a emissão da AE?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
