INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316450, 'LOGISTICA-TABORDA', 'O operador se identificou informando saudação?', 'A identificação profissionaliza o atendimento e garante clareza sobre quem está ligando. | Exemplo oficial: "Bom dia/Boa tarde/Boa noite."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316451, 'LOGISTICA-TABORDA', 'Utilizou linguagem apropriada? (Sem usar gírias ou estereótipos de apoio)', 'A linguagem profissional e adequada assegura que a interação seja respeitosa e clara.', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316452, 'LOGISTICA-TABORDA', 'Fluxo do atendimento correspondeu à solicitação inicial? (Foco no atendimento)', 'Evita desvio do foco e garante que o cliente receba a ajuda necessária sem interrupções desnecessárias.', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316453, 'LOGISTICA-TABORDA', 'Realizou o preenchimento de ociosidade? (Não deixando atendimento sem retorno por mais de 3min)', 'Manter o atendimento ágil e sem interrupções prolongadas garante a boa experiência para o cliente.', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316454, 'LOGISTICA-TABORDA', 'Realizou um atendimento cordial com educação? (Utilizando "obrigado"/"por favor"/"senhor")', 'A cordialidade e a educação fazem parte do atendimento de excelência. | Exemplo oficial: "Me informe sua placa por favor"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316455, 'LOGISTICA-TABORDA', 'Questionou se podia encerrar o atendimento?', 'A confirmação do cliente antes de encerrar a interação demonstra cuidado e respeito pela necessidade do cliente. | Exemplo oficial: "Posso ajudar com algo mais ou posso encerrar nossa conversa?"', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316456, 'LOGISTICA-TABORDA', 'Encerrou somente no tempo ocioso padrão? (3min)', 'Garantir que o atendimento só seja encerrado após o tempo padrão evita a interrupção prematura do serviço.', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
