INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316510, 'MONDELEZ-MONITORAMENTO-II', 'Confirmou com quem está falando?', 'Garante que a informação seja passada para a pessoa correta. | Exemplo oficial: "Por gentileza, estou falando com [Nome do Cliente/Responsável]?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316511, 'MONDELEZ-MONITORAMENTO-II', 'Confirmou se a pessoa é motorista ou transportadora?', 'Garante que o atendimento seja direcionado corretamente, evitando mal-entendidos. | Exemplo oficial: "Por gentileza, pode me informar se você é motorista ou da transportadora?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316512, 'MONDELEZ-MONITORAMENTO-II', 'Solicitou o número da Nota Fiscal? (Confirmar 2x caso não localize)', 'Garante que todas as informações necessárias sejam verificadas corretamente para resolver a ocorrência. | Exemplo oficial: "Você pode me fornecer o número da nota fiscal?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316513, 'MONDELEZ-MONITORAMENTO-II', 'Confirmou o nome do cliente que está no nosso sistema? [Informe o cliente]', 'Garante que as informações no sistema correspondem às do cliente, evitando possíveis erros. | Exemplo oficial: "Qual o nome do cliente?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316514, 'MONDELEZ-MONITORAMENTO-II', 'Confirmou o telefone do motorista?', 'Assegura que o contato correto com o motorista seja feito, agilizando a resolução da ocorrência. | Exemplo oficial: "Confirma pra mim o número do motorista"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316515, 'MONDELEZ-MONITORAMENTO-II', 'Questionou o motivo da ocorrência?', 'Identifica rapidamente o motivo da ocorrência para tomar ações corretivas e resolver o problema com mais eficiência. | Exemplo oficial: "Você poderia me informar qual o motivo da ocorrência?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316516, 'MONDELEZ-MONITORAMENTO-II', 'Questionou a data de agendamento?', 'Evita atrasos, conflitos e garante organização logística. | Exemplo oficial: "Possui uma data para o agendamento?"', 0.95, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316517, 'MONDELEZ-MONITORAMENTO-II', 'Questionou se possui notas de outros clientes?', 'Evita erros, garante conferência correta e organiza a logística. | Exemplo oficial: "Você possui notas de outros clientes?"', 0.95, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316518, 'MONDELEZ-MONITORAMENTO-II', 'Informou o número da Ocorrência gerada no sistema?', 'Registra corretamente a ocorrência para rastrear o progresso e garantir que a situação seja resolvida. | Exemplo oficial: "A ocorrência gerada no sistema é [número da ocorrência], podemos dar andamento?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316519, 'MONDELEZ-MONITORAMENTO-II', 'Solicitou que retorne o contato após 2 horas para realizar uma atuação da ocorrência?', 'Garante que o processo de follow-up seja realizado, permitindo que a situação seja devidamente acompanhada. | Exemplo oficial: "Por favor, preciso que retorne o contato daqui 2 horas para que possamos realizar a atualização da ocorrência."', 0.95, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316520, 'MONDELEZ-MONITORAMENTO-II', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316521, 'MONDELEZ-MONITORAMENTO-II', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316522, 'MONDELEZ-MONITORAMENTO-II', 'Evitou silêncios prolongados (mais de 60 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou realizando a abertura do seu chamado. Aguarde mais um momento."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316523, 'MONDELEZ-MONITORAMENTO-II', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316524, 'MONDELEZ-MONITORAMENTO-II', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de girias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316525, 'CHECKLIST-VEICULO', 'O operador se identificou informando saudação.', 'A identificação profissionaliza o atendimento e garante clareza sobre quem está ligando. | Exemplo oficial: "Bom dia/Boa tarde/Boa noite."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316526, 'CHECKLIST-VEICULO', 'Enviou o auto texto perguntando qual o tipo de veículo?', 'A coleta correta da informação inicial é essencial para garantir a precisão do atendimento. | Exemplo oficial: "Qual o tipo do veículo? 1 - Carreta: Baú 2 - Carreta: Graneleiro - Saider - Contêiner 3 - Toco-Truck: Baú 4 - Toco-Truck: Graneleiro - Saider - Contêiner 5 - Outro: Nos informe o tipo"', 0.5, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316527, 'CHECKLIST-VEICULO', 'Seguiu corretamente o fluxo do checklist conforme a solicitação inicial?', 'Evita omissões ou atalhos que possam comprometer a precisão do checklist.', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316528, 'CHECKLIST-VEICULO', 'Realizou um atendimento cordial, utilizando linguagem apropriada?', 'Garante que a interação seja profissional e respeitosa. | Exemplo oficial: "Por favor, pode me informar quando realizar a solicitação"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316529, 'CHECKLIST-VEICULO', 'Informou o status final do checklist (aprovado ou reprovado)?', 'Transmite claramente a situação do veículo, evitando confusão. | Exemplo oficial: "Senhor(a) informo que o veículo está *APROVADO* no Checklist. Agradecemos o contato!"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316530, 'CHECKLIST-VEICULO', 'Se reprovado, informou corretamente o motivo da reprovação?', 'A comunicação clara e detalhada é importante para a compreensão do problema. | Exemplo oficial: "Prezado (a), informo que seu veículo foi *REPROVADO* por: sensor de baú. Dessa forma, favor verificar com o responsável para realizar manutenção no item que ficou reprovado e posteriormente agendar um novo check list via SIL. Agradecemos o contato!"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316531, 'CHECKLIST-VEICULO', 'Anexou imagens dos testes no SIL, correspondentes ao veículo e tecnologia analisada?', 'A documentação visual ajuda a validar o processo e oferece respaldo para a decisão.', 2.0, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316532, 'CHECKLIST-VEICULO', 'A informação passada no atendimento corresponde ao que foi registrado no SIL?', 'Verifica a consistência das informações entre o atendimento e o sistema.', 2.0, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316533, 'CHECKLIST-VEICULO', 'Encerrou o checklist no SIL em até 5 minutos após informar o status final?', 'Garante agilidade na atualização das informações, evitando atrasos.', 0.3, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316534, 'CHECKLIST-VEICULO', 'Realizou a despedida padrão com cordialidade?', 'Terminar o atendimento de maneira educada fortalece a boa impressão do serviço. | Exemplo oficial: "Atendimento finalizado, obrigado por utilizar nossos serviços."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316535, 'CHECKLIST-VEICULO', 'Encerrou o atendimento no Weon em até 5 minutos após informar o status final do checklist?', 'Evita filas de atendimento e promove agilidade no processo.', 0.3, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
