INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316549, 'RECEPTIVO-CHATBOT', 'O operador se identificou informando saudação?', 'A identificação profissionaliza o atendimento e garante clareza sobre quem está ligando. | Exemplo oficial: "Bom dia/Boa tarde/Boa noite."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316550, 'RECEPTIVO-CHATBOT', 'Utilizou linguagem apropriada? (Sem usar gírias ou estereótipos de apoio)', 'A linguagem profissional e adequada assegura que a interação seja respeitosa e clara.', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316551, 'RECEPTIVO-CHATBOT', 'Fluxo do atendimento correspondeu à solicitação inicial? (Foco no atendimento)', 'Evita desvio do foco e garante que o cliente receba a ajuda necessária sem interrupções desnecessárias.', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316552, 'RECEPTIVO-CHATBOT', 'Realizou o preenchimento de ociosidade? (Não deixando atendimento sem retorno por mais de 3min)', 'Manter o atendimento ágil e sem interrupções prolongadas garante a boa experiência para o cliente.', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316553, 'RECEPTIVO-CHATBOT', 'Realizou um atendimento cordial com educação? (Utilizando "obrigado"/"por favor"/"senhor")', 'A cordialidade e a educação fazem parte do atendimento de excelência. | Exemplo oficial: "Me informe sua placa por favor"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316554, 'RECEPTIVO-CHATBOT', 'Questionou se podia encerrar o atendimento?', 'A confirmação do cliente antes de encerrar a interação demonstra cuidado e respeito pela necessidade do cliente. | Exemplo oficial: "Posso ajudar com algo mais ou posso encerrar nossa conversa?"', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316555, 'RECEPTIVO-CHATBOT', 'Encerrou somente no tempo ocioso padrão? (3min)', 'Garantir que o atendimento só seja encerrado após o tempo padrão evita a interrupção prematura do serviço.', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316556, 'RECEPTIVO-CHATBOT', 'Foi realizado a despedida final padrão?', 'A despedida padrão demonstra cordialidade e encerra o atendimento de forma profissional. | Exemplo oficial: "Antendimento finalizado!"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
