INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316563, 'CELULA-RECEPTIVO', 'Questionou se podia encerrar o atendimento?', 'A confirmação do cliente antes de encerrar a interação demonstra cuidado e respeito pela necessidade do cliente. | Exemplo oficial: "Posso ajudar com algo mais ou posso encerrar nossa conversa?"', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316564, 'CELULA-RECEPTIVO', 'Encerrou somente no tempo ocioso padrão? (3min)', 'Garantir que o atendimento só seja encerrado após o tempo padrão evita a interrupção prematura do serviço.', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316565, 'CELULA-RECEPTIVO', 'Foi realizado a despedida final padrão?', 'A despedida padrão demonstra cordialidade e encerra o atendimento de forma profissional. | Exemplo oficial: "Antendimento finalizado!"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316566, 'CELULA-RECEPTIVO', 'Foi realizada a qualificação correta do atendimento?', 'A qualificação correta ajuda a categorizar e analisar a qualidade do atendimento realizado.', 0.3, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316567, 'DISTRIBUICAO-PRIORITARIO-MOT', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316568, 'DISTRIBUICAO-PRIORITARIO-MOT', 'Nome?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316569, 'DISTRIBUICAO-PRIORITARIO-MOT', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316570, 'DISTRIBUICAO-PRIORITARIO-MOT', 'O operador confirmou a senha de segurança antes de prosseguir?', 'A verificação de senha protege a comunicação e evita repasses indevidos de informações. | Exemplo oficial: "Antes de prosseguirmos, poderia me confirmar sua senha de segurança, por favor?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316571, 'DISTRIBUICAO-PRIORITARIO-MOT', 'O operador informou claramente o motivo do contato?', 'O motorista precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta detectado no sistema. Preciso verificar sua situação."', 1.03, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316572, 'DISTRIBUICAO-PRIORITARIO-MOT', 'O operador confirmou a localização e a condição do motorista?', 'Ter a posição exata e saber se há risco permite uma melhor análise da ocorrência. | Exemplo oficial: "Pode me confirmar onde exatamente você está agora? Movimento ou parado?"', 1.7, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316573, 'DISTRIBUICAO-PRIORITARIO-MOT', 'O operador identificou o motivo do alerta? (Sinistro, manutenção, problema técnico, acionamento indevido, etc.)', 'A causa do alerta precisa ser identificada rapidamente para tomada de decisão. | Exemplo oficial: "Consegue me informar o que ocorreu para esse alerta ter subido para mim?"', 1.92, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316574, 'DISTRIBUICAO-PRIORITARIO-MOT', 'O operador solicitou vídeo do veículo nos casos necessários (Painel violado, Botão de pânico, Perda de Bateria, Teclado Desconectado, Sensor de desengate e baú)?', 'A solicitação do vídeo é essencial para análise mais detalhada e para garantir a segurança do motorista e da carga. | Exemplo oficial: "O senhor consegue enviar para nós um vídeo no WhatsApp? No vídeo precisa falar seu nome, senha de segurança, data e horário atuais”', 1.7, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316575, 'DISTRIBUICAO-PRIORITARIO-MOT', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316576, 'DISTRIBUICAO-PRIORITARIO-MOT', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316577, 'DISTRIBUICAO-PRIORITARIO-MOT', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316578, 'DISTRIBUICAO-PRIORITARIO-MOT', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: Exemplo: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Motorista/Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316579, 'DISTRIBUICAO-PRIORITARIO-MOT', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316580, 'DISTRIBUICAO-PRIORITARIO-MOT', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de gírias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316581, 'DISTRIBUICAO-PRIORITARIO-CLI', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
