INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316601, 'DISTRIBUICAO-POSICAO-MOT', 'O operador confirmou a localização atual do motorista? (Em movimento/parado, cidade e referência de local)', 'É essencial identificar se a falta de sinal está relacionada ao deslocamento ou a um local de sombra de sinal. | Exemplo oficial: "O caminhão está parado ou em movimento? Você pode me passar um ponto de referência posto, km da rodovia? Qual a cidade?"', 1.22, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316602, 'DISTRIBUICAO-POSICAO-MOT', 'Passou orientações para forçar posicionamento do rastreador? (Envio de mensagem, reset de bateria, etc.)', 'Medidas corretivas ajudam a restabelecer o sinal, garantindo continuidade no monitoramento. | Exemplo oficial: "Precisamos tentar restabelecer o sinal. Você pode desligar e religar a chave geral do veículo? Ou enviar uma mensagem no teclado?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316603, 'DISTRIBUICAO-POSICAO-MOT', 'O operador procurou identificar o motivo da perda de sinal? (Embaixo de cobertura, área sem sinal de celular, falha no rastreador, etc.)', 'Compreender a causa ajuda na tomada de decisão e no suporte adequado ao motorista. | Exemplo oficial: "Você está em um local coberto, como um túnel ou garagem? Sabe me informar se a região é ruim de sinal?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316604, 'DISTRIBUICAO-POSICAO-MOT', 'O operador informou os riscos operacionais e de seguro caso o sinal não restabelecer?', 'Evita prejuízos, melhora a segurança e assegura responsabilidade e garante monitoramento contínuo. | Exemplo oficial: "Caso ocorra um sinistro com o sinal desatualizado, pode haver problemas com a cobertura do seguro da carga e do veículo."', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
