INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316650, 'DISTRIBUICAO-PARADA-CLI', 'O operador confirmou se os pontos de parada autorizada foram passados ao motorista antes do início da viagem?', 'Verifica se o motorista tinha conhecimento prévio das regras de parada. | Exemplo oficial: "O motorista recebeu os pontos de parada autorizada antes do início da viagem? Estava ciente das restrições?"', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316651, 'DISTRIBUICAO-PARADA-CLI', 'O operador informou ao cliente sobre os riscos operacionais e de seguro caso a parada indevida permaneça?', 'Esclarece ao cliente o impacto da parada não autorizada na cobertura do seguro e segurança da carga. | Exemplo oficial: "Caso ocorra um sinistro enquanto o veículo está fora dos pontos autorizados, pode haver impacto na cobertura do seguro da carga e do veículo."', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316652, 'DISTRIBUICAO-PARADA-CLI', 'O operador indicou medidas de segurança ao cliente? (Ex.: Seguir até posto autorizado, acionar escolta, pronta resposta, etc.)', 'Sugere alternativas para mitigar riscos e reforçar a segurança da operação. | Exemplo oficial: "Solicitamos que oriente o motorista a seguir até o posto autorizado mais próximo. Caso a parada persista, poderá ter problemas com a seguradora.', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
