INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316661, 'DISTRIBUICAO-DESVIO-MOT', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316662, 'DISTRIBUICAO-DESVIO-MOT', 'O operador confirmou a senha de segurança antes de prosseguir?', 'A verificação de senha protege a comunicação e evita repasses indevidos de informações. | Exemplo oficial: "Antes de prosseguirmos, poderia me confirmar sua senha de segurança, por favor?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316663, 'DISTRIBUICAO-DESVIO-MOT', 'O operador informou claramente o motivo do contato?', 'O motorista precisa entender rapidamente o problema para colaborar com a solução. | Exemplo oficial: "Estamos identificando um desvio de rota no seu trajeto e precisamos entender a situação."', 1.03, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316664, 'DISTRIBUICAO-DESVIO-MOT', 'O operador confirmou o motivo do desvio de rota?', 'Identificar o motivo do desvio é essencial para definir as próximas ações e validar se houve uma alteração planejada. | Exemplo oficial: "O que aconteceu para que você saísse da rota planejada?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316665, 'DISTRIBUICAO-DESVIO-MOT', 'Confirmou se o motorista recebeu o plano de viagem e instruções de rastreamento?', 'Garante que o motorista tinha ciência do trajeto e das regras de monitoramento antes do desvio. | Exemplo oficial: "Você recebeu o plano de viagem com as instruções de rastreamento antes do início da viagem?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316666, 'DISTRIBUICAO-DESVIO-MOT', 'Orientou o motorista a retornar para a rota ou permanecer parado até confirmação com o cliente?', 'Dependendo do motivo do desvio, é necessário orientar a retomada do trajeto ou aguardar autorização. | Exemplo oficial: "Por segurança, oriento que retorne ao trajeto previsto. Caso haja alguma mudança, vamos confirmar com o cliente."', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316667, 'DISTRIBUICAO-DESVIO-MOT', 'Coletou qual itinerário o motorista está realizando?', 'Ajuda a entender se houve uma falha na programação da rota ou se o motorista recebeu uma nova orientação de terceiros. | Exemplo oficial: "Por onde o senhor vai seguir agora? Esse trajeto foi repassado por alguém?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316668, 'DISTRIBUICAO-DESVIO-MOT', 'O operador informou os riscos operacionais e de seguro caso o motorista continue fora da rota?', 'Esclarece ao motorista que a saída não autorizada da rota pode impactar na cobertura do seguro em caso de sinistro. | Exemplo oficial: "Caso ocorra um sinistro fora da rota homologada, pode haver problemas com a cobertura do seguro da carga e do veículo."', 1.12, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316669, 'DISTRIBUICAO-DESVIO-MOT', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316670, 'DISTRIBUICAO-DESVIO-MOT', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316671, 'DISTRIBUICAO-DESVIO-MOT', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316672, 'DISTRIBUICAO-DESVIO-MOT', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: "Contato registrado: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316673, 'DISTRIBUICAO-DESVIO-MOT', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316674, 'DISTRIBUICAO-DESVIO-MOT', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de girias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316675, 'DISTRIBUICAO-DESVIO-CLI', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316676, 'DISTRIBUICAO-DESVIO-CLI', 'Nome?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316677, 'DISTRIBUICAO-DESVIO-CLI', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316678, 'DISTRIBUICAO-DESVIO-CLI', 'Confirmou com quem está falando?', 'Garante que a informação seja passada para a pessoa correta. | Exemplo oficial: "Por gentileza, com quem eu falo?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316679, 'DISTRIBUICAO-DESVIO-CLI', 'O operador informou claramente o motivo do contato?', 'O cliente precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta de desvio de rota detectado no sistema. Preciso verificar a situação."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316680, 'DISTRIBUICAO-DESVIO-CLI', 'O operador enfatizou ao cliente que estava atuando em uma suspeita de sinistro?', 'Alerta o cliente sobre a gravidade da situação, reforçando a necessidade de atenção e suporte imediato. | Exemplo oficial: "Estamos tratando este caso como uma suspeita de sinistro e intensificando as tratativas para garantir a segurança da carga e do veículo."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316681, 'DISTRIBUICAO-DESVIO-CLI', 'O operador informou as ações adotadas até o momento? (Resumir os contatos/tratativas com ou sem sucesso)', 'Garante que o cliente tenha clareza sobre as tratativas realizadas e próximos passos. | Exemplo oficial: "Já tentamos contato com o motorista e não obtivemos retorno. Também acionamos o ponto de apoio mais próximo e seguimos monitorando a movimentação do veículo."', 1.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316682, 'DISTRIBUICAO-DESVIO-CLI', 'O operador informou o trajeto que o motorista está realizando e o que estava programado na rota?', 'Ajuda o cliente a entender a divergência e avaliar o risco da situação. | Exemplo oficial: "O motorista deveria seguir pela [Rodovia X], mas desviou para a [Rodovia Y] sem comunicação prévia."', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316683, 'DISTRIBUICAO-DESVIO-CLI', 'O operador questionou se o cliente tem conhecimento do motivo do desvio? O motorista informou antecipadamente?', 'Verifica se o cliente recebeu algum aviso do motorista, evitando alarmes desnecessários. | Exemplo oficial: "O motorista entrou em contato com vocês para informar que iria desviar? Há alguma orientação interna sobre essa mudança de rota?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316684, 'DISTRIBUICAO-DESVIO-CLI', 'O operador confirmou se o motorista recebeu o plano de viagem e instruções de rastreamento antes da viagem?', 'Garante que o motorista tinha ciência da rota planejada e das regras de rastreamento. | Exemplo oficial: "O motorista recebeu o plano de viagem com a rota definida e as instruções de rastreamento antes da viagem?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316685, 'DISTRIBUICAO-DESVIO-CLI', 'O operador indicou medidas de segurança ao cliente? (Ex.: Retornar a rota correta ou realizar o ajuste no sistema)', 'Sugere alternativas para mitigar riscos e reforçar a segurança da operação. | Exemplo oficial: "Solicitamos que oriente o motorista a seguir pela rota correta ou que seja feita a alteração via SIL."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
