INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316709, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316710, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'Confirmou com quem está falando?', 'Garante que a informação seja passada para a pessoa correta. | Exemplo oficial: "Por gentileza, com quem eu falo?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316711, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'O operador passou detalhes do evento que indicam a suspeita?', 'O operador informou claramente o motivo do contato? | Exemplo oficial: "Somos uma Gerenciadora de Risco, e estamos monitorando um veículo que gerou um alerta de [alerta] e não temos contato com o motorista, gostaríamos de solicitar apoio nessa ocorrência".', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316712, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'O operador informou os dados e as características do conjunto e do motorista? (cavalo, carreta, cor, modelo)', 'Garante que a abordagem seja feita no veículo correto. | Exemplo oficial: "Trata-se de um [modelo] de cor [cor], placa [placa], puxando uma carreta [tipo]."', 1.35, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316713, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'O operador passou detalhes do local da ocorrência? (Rodovia, Referência, KM)', 'Ajuda a equipe policial a identificar com precisão a localização para uma resposta mais rápida. | Exemplo oficial: "O último posicionamento do veículo foi na BR-101, próximo ao KM 75, sentido sul."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316714, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'O operador solicitou deslocamento e/ou reporte da ocorrência para patrulhamento?', 'Garante que a solicitação seja clara e direta, aumentando a chance de uma abordagem rápida. | Exemplo oficial: "Solicitamos apoio para patrulhamento e abordagem do veículo em situação suspeita."', 1.5, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316715, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'O operador deixou telefone de contato para retorno?', 'Garante um canal de comunicação aberto para atualizações e suporte adicional. | Exemplo oficial: "Podem retornar para o número 0800 727 6101 Opção 3 para qualquer atualização."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316716, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'O operador utilizou o alfabeto fonético ao passar informações?', 'Evita erros na transmissão de placas e códigos, garantindo clareza. | Exemplo oficial: "Placa do veículo: Alfa, Bravo, Charlie, primeiro, segundo, terceiro, quarto."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316717, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316718, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316719, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316720, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: "Contato registrado: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316721, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316722, 'DISTRIBUICAO-PRIORITARIO-POLICIA', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de girias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
