INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316898, 'FENIX-PRIORITARIO-CLI', 'O operador enfatizou ao cliente que estava atuando em uma suspeita de sinistro?', 'Alerta o cliente sobre a gravidade da situação, reforçando a necessidade de atenção e suporte imediato. | Exemplo oficial: "Estamos tratando este caso como uma suspeita de sinistro e intensificando as tratativas para garantir a segurança da carga e do veículo."', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316899, 'FENIX-PRIORITARIO-CLI', 'O operador informou as ações adotadas até o momento?', 'Garante que o cliente tenha clareza sobre as tratativas realizadas e próximos passos. | Exemplo oficial: "Já realizamos tentativas de contato com o motorista e ponto de apoio, além de enviar comandos ao rastreador, sem sucesso até o momento."', 1.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316900, 'FENIX-PRIORITARIO-CLI', 'O operador informou corretamente o local onde gerou o alerta? (Cidade, estado, referência como rodovia, posto, mecânica, etc.)', 'Ajuda o cliente a entender o contexto e avaliar o risco da situação. | Exemplo oficial: "O veículo estava na cidade de [cidade], próximo ao [posto/mecânica/km da rodovia]."', 1.8, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
