INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316945, 'FENIX-PARADA-MOT', 'O operador confirmou o motivo pelo qual o motorista parou em local indevido?', 'Identificar a razão da parada permite avaliar riscos e definir a melhor orientação. | Exemplo oficial: "Você precisou parar por algum motivo específico? Houve alguma falha no veículo?"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316946, 'FENIX-PARADA-MOT', 'O operador confirmou se o motorista recebeu o plano de viagem e instruções de rastreamento?', 'Garantir que o motorista esteja ciente das regras e que tenha em mãos os locais homologados. | Exemplo oficial: "Você recebeu todas as orientações sobre os locais homologados para parada?"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316947, 'FENIX-PARADA-MOT', 'O operador orientou o motorista a reiniciar a viagem e seguir para um local homologado?', 'A saída imediata do local reduz riscos operacionais e de segurança. | Exemplo oficial: "Por favor, retome sua viagem e siga para um local autorizado o mais breve possível."', 1.32, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316948, 'FENIX-PARADA-MOT', 'O operador informou os riscos operacionais da parada indevida, incluindo problemas com seguro?', 'Deixar claro os impactos de uma parada irregular faz com que o motorista compreenda a importância da orientação. | Exemplo oficial: "Essa parada pode comprometer a cobertura do seguro em caso de sinistro. Precisamos que o veículo esteja em um local adequado."', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
