INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316961, 'FENIX-PARADA-CLI', 'O operador informou corretamente o local da parada? (Cidade, estado, referência como rodovia, posto, mecânica, etc.)', 'Ajuda o cliente a entender o contexto e avaliar o risco da situação. | Exemplo oficial: "O veículo está parado em [cidade], próximo a [posto/mecânica/km da rodovia]."', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316962, 'FENIX-PARADA-CLI', 'O operador confirmou se os pontos de parada autorizada foram passados ao motorista antes do início da viagem?', 'Verifica se o motorista tinha conhecimento prévio das regras de parada. | Exemplo oficial: "O motorista recebeu os pontos de parada autorizada antes do início da viagem? Estava ciente das restrições?"', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316963, 'FENIX-PARADA-CLI', 'O operador informou ao cliente sobre os riscos operacionais e de seguro caso a parada indevida permaneça?', 'Esclarece ao cliente o impacto da parada não autorizada na cobertura do seguro e segurança da carga. | Exemplo oficial: "Caso ocorra um sinistro enquanto o veículo está fora dos pontos autorizados, pode haver impacto na cobertura do seguro da carga e do veículo."', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316964, 'FENIX-PARADA-CLI', 'O operador indicou medidas de segurança ao cliente? (Ex.: Seguir até posto autorizado, acionar escolta, pronta resposta, etc.)', 'Sugere alternativas para mitigar riscos e reforçar a segurança da operação. | Exemplo oficial: "Solicitamos que oriente o motorista a seguir até o posto autorizado mais próximo. Caso a parada persista, poderá ter problemas com a seguradora.', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316965, 'FENIX-PARADA-CLI', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316966, 'FENIX-PARADA-CLI', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316967, 'FENIX-PARADA-CLI', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316968, 'FENIX-PARADA-CLI', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: "Contato registrado: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316969, 'FENIX-PARADA-CLI', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316970, 'FENIX-PARADA-CLI', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de girias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316971, 'FENIX-DESVIO-MOT', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316972, 'FENIX-DESVIO-MOT', 'Nome?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316973, 'FENIX-DESVIO-MOT', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316974, 'FENIX-DESVIO-MOT', 'O operador confirmou a senha de segurança antes de prosseguir?', 'A verificação de senha protege a comunicação e evita repasses indevidos de informações. | Exemplo oficial: "Antes de prosseguirmos, poderia me confirmar sua senha de segurança, por favor?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316975, 'FENIX-DESVIO-MOT', 'O operador informou claramente o motivo do contato?', 'O motorista precisa entender rapidamente o problema para colaborar com a solução. | Exemplo oficial: "Estamos identificando um desvio de rota no seu trajeto e precisamos entender a situação."', 1.03, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316976, 'FENIX-DESVIO-MOT', 'O operador confirmou o motivo do desvio de rota?', 'Identificar o motivo do desvio é essencial para definir as próximas ações e validar se houve uma alteração planejada. | Exemplo oficial: "O que aconteceu para que você saísse da rota planejada?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316977, 'FENIX-DESVIO-MOT', 'Confirmou se o motorista recebeu o plano de viagem e instruções de rastreamento?', 'Garante que o motorista tinha ciência do trajeto e das regras de monitoramento antes do desvio. | Exemplo oficial: "Você recebeu o plano de viagem com as instruções de rastreamento antes do início da viagem?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316978, 'FENIX-DESVIO-MOT', 'Orientou o motorista a retornar para a rota ou permanecer parado até confirmação com o cliente?', 'Dependendo do motivo do desvio, é necessário orientar a retomada do trajeto ou aguardar autorização. | Exemplo oficial: "Por segurança, oriento que retorne ao trajeto previsto. Caso haja alguma mudança, vamos confirmar com o cliente."', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316979, 'FENIX-DESVIO-MOT', 'Coletou qual itinerário o motorista está realizando?', 'Ajuda a entender se houve uma falha na programação da rota ou se o motorista recebeu uma nova orientação de terceiros. | Exemplo oficial: "Por onde o senhor vai seguir agora? Esse trajeto foi repassado por alguém?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316980, 'FENIX-DESVIO-MOT', 'O operador informou os riscos operacionais e de seguro caso o motorista continue fora da rota?', 'Esclarece ao motorista que a saída não autorizada da rota pode impactar na cobertura do seguro em caso de sinistro. | Exemplo oficial: "Caso ocorra um sinistro fora da rota homologada, pode haver problemas com a cobertura do seguro da carga e do veículo."', 1.12, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
