INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316991, 'FENIX-DESVIO-CLI', 'O operador informou claramente o motivo do contato?', 'O cliente precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta de desvio de rota detectado no sistema. Preciso verificar a situação."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316992, 'FENIX-DESVIO-CLI', 'O operador enfatizou ao cliente que estava atuando em uma suspeita de sinistro?', 'Alerta o cliente sobre a gravidade da situação, reforçando a necessidade de atenção e suporte imediato. | Exemplo oficial: "Estamos tratando este caso como uma suspeita de sinistro e intensificando as tratativas para garantir a segurança da carga e do veículo."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316993, 'FENIX-DESVIO-CLI', 'O operador informou as ações adotadas até o momento? (Resumir os contatos/tratativas com ou sem sucesso)', 'Garante que o cliente tenha clareza sobre as tratativas realizadas e próximos passos. | Exemplo oficial: "Já tentamos contato com o motorista e não obtivemos retorno. Também acionamos o ponto de apoio mais próximo e seguimos monitorando a movimentação do veículo."', 1.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316994, 'FENIX-DESVIO-CLI', 'O operador informou o trajeto que o motorista está realizando e o que estava programado na rota?', 'Ajuda o cliente a entender a divergência e avaliar o risco da situação. | Exemplo oficial: "O motorista deveria seguir pela [Rodovia X], mas desviou para a [Rodovia Y] sem comunicação prévia."', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316995, 'FENIX-DESVIO-CLI', 'O operador questionou se o cliente tem conhecimento do motivo do desvio? O motorista informou antecipadamente?', 'Verifica se o cliente recebeu algum aviso do motorista, evitando alarmes desnecessários. | Exemplo oficial: "O motorista entrou em contato com vocês para informar que iria desviar? Há alguma orientação interna sobre essa mudança de rota?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (316996, 'FENIX-DESVIO-CLI', 'O operador confirmou se o motorista recebeu o plano de viagem e instruções de rastreamento antes da viagem?', 'Garante que o motorista tinha ciência da rota planejada e das regras de rastreamento. | Exemplo oficial: "O motorista recebeu o plano de viagem com a rota definida e as instruções de rastreamento antes da viagem?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
