INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317038, 'TRANSFERENCIA-PRIORITARIO-MOT', 'O operador confirmou a senha de segurança antes de prosseguir?', 'A verificação de senha protege a comunicação e evita repasses indevidos de informações. | Exemplo oficial: "Antes de prosseguirmos, poderia me confirmar sua senha de segurança, por favor?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317039, 'TRANSFERENCIA-PRIORITARIO-MOT', 'O operador informou claramente o motivo do contato?', 'O motorista precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta detectado no sistema. Preciso verificar sua situação."', 1.03, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317040, 'TRANSFERENCIA-PRIORITARIO-MOT', 'O operador confirmou a localização e a condição do motorista?', 'Ter a posição exata e saber se há risco permite uma melhor análise da ocorrência. | Exemplo oficial: "Pode me confirmar onde exatamente você está agora? Movimento ou parado?"', 1.7, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317041, 'TRANSFERENCIA-PRIORITARIO-MOT', 'O operador identificou o motivo do alerta? (Sinistro, manutenção, problema técnico, acionamento indevido, etc.)', 'A causa do alerta precisa ser identificada rapidamente para tomada de decisão. | Exemplo oficial: "Consegue me informar o que ocorreu para esse alerta ter subido para mim?"', 1.92, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317042, 'TRANSFERENCIA-PRIORITARIO-MOT', 'O operador solicitou vídeo do veículo nos casos necessários (Painel violado, Botão de pânico, Perda de Bateria, Teclado Desconectado, Sensor de desengate e baú)?', 'A solicitação do vídeo é essencial para análise mais detalhada e para garantir a segurança do motorista e da carga. | Exemplo oficial: "O senhor consegue enviar para nós um vídeo no WhatsApp? No vídeo precisa falar seu nome, senha de segurança, data e horário atuais”', 1.7, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
