INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317054, 'TRANSFERENCIA-PRIORITARIO-CLI', 'O operador enfatizou ao cliente que estava atuando em uma suspeita de sinistro?', 'Alerta o cliente sobre a gravidade da situação, reforçando a necessidade de atenção e suporte imediato. | Exemplo oficial: "Estamos tratando este caso como uma suspeita de sinistro e intensificando as tratativas para garantir a segurança da carga e do veículo."', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317055, 'TRANSFERENCIA-PRIORITARIO-CLI', 'O operador informou as ações adotadas até o momento?', 'Garante que o cliente tenha clareza sobre as tratativas realizadas e próximos passos. | Exemplo oficial: "Já realizamos tentativas de contato com o motorista e ponto de apoio, além de enviar comandos ao rastreador, sem sucesso até o momento."', 1.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317056, 'TRANSFERENCIA-PRIORITARIO-CLI', 'O operador informou corretamente o local onde gerou o alerta? (Cidade, estado, referência como rodovia, posto, mecânica, etc.)', 'Ajuda o cliente a entender o contexto e avaliar o risco da situação. | Exemplo oficial: "O veículo estava na cidade de [cidade], próximo ao [posto/mecânica/km da rodovia]."', 1.8, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317057, 'TRANSFERENCIA-PRIORITARIO-CLI', 'O operador confirmou os contatos atuais do condutor?', 'Garante que os números utilizados estão corretos, evitando tentativas de contato desatualizadas. | Exemplo oficial: "O número de telefone que temos registrado para o condutor é [número]. Confirma se está correto ou há outro contato atualizado?"', 1.8, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317058, 'TRANSFERENCIA-PRIORITARIO-CLI', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317059, 'TRANSFERENCIA-PRIORITARIO-CLI', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317060, 'TRANSFERENCIA-PRIORITARIO-CLI', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317061, 'TRANSFERENCIA-PRIORITARIO-CLI', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: Exemplo: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317062, 'TRANSFERENCIA-PRIORITARIO-CLI', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317063, 'TRANSFERENCIA-PRIORITARIO-CLI', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de gírias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317064, 'TRANSFERENCIA-POSICAO-MOT', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317065, 'TRANSFERENCIA-POSICAO-MOT', 'Nome?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317066, 'TRANSFERENCIA-POSICAO-MOT', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317067, 'TRANSFERENCIA-POSICAO-MOT', 'O operador confirmou a senha de segurança antes de prosseguir?', 'A verificação de senha protege a comunicação e evita repasses indevidos de informações. | Exemplo oficial: "Antes de prosseguirmos, poderia me confirmar sua senha de segurança, por favor?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317068, 'TRANSFERENCIA-POSICAO-MOT', 'O operador informou claramente o motivo do contato?', 'O motorista precisa entender rapidamente o problema para colaborar com a solução. | Exemplo oficial: "Estamos identificando a perda do sinal do rastreador e precisamos entender a situação."', 1.03, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317069, 'TRANSFERENCIA-POSICAO-MOT', 'O operador confirmou a localização atual do motorista? (Em movimento/parado, cidade e referência de local)', 'É essencial identificar se a falta de sinal está relacionada ao deslocamento ou a um local de sombra de sinal. | Exemplo oficial: "O caminhão está parado ou em movimento? Você pode me passar um ponto de referência posto, km da rodovia? Qual a cidade?"', 1.22, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317070, 'TRANSFERENCIA-POSICAO-MOT', 'Passou orientações para forçar posicionamento do rastreador? (Envio de mensagem, reset de bateria, etc.)', 'Medidas corretivas ajudam a restabelecer o sinal, garantindo continuidade no monitoramento. | Exemplo oficial: "Precisamos tentar restabelecer o sinal. Você pode desligar e religar a chave geral do veículo? Ou enviar uma mensagem no teclado?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317071, 'TRANSFERENCIA-POSICAO-MOT', 'O operador procurou identificar o motivo da perda de sinal? (Embaixo de cobertura, área sem sinal de celular, falha no rastreador, etc.)', 'Compreender a causa ajuda na tomada de decisão e no suporte adequado ao motorista. | Exemplo oficial: "Você está em um local coberto, como um túnel ou garagem? Sabe me informar se a região é ruim de sinal?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317072, 'TRANSFERENCIA-POSICAO-MOT', 'O operador informou os riscos operacionais e de seguro caso o sinal não restabelecer?', 'Evita prejuízos, melhora a segurança e assegura responsabilidade e garante monitoramento contínuo. | Exemplo oficial: "Caso ocorra um sinistro com o sinal desatualizado, pode haver problemas com a cobertura do seguro da carga e do veículo."', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
