INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317083, 'TRANSFERENCIA-POSICAO-CLI', 'O operador informou claramente o motivo do contato?', 'O cliente precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta de perda de posição detectado no sistema. Preciso verificar a situação."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317084, 'TRANSFERENCIA-POSICAO-CLI', 'O operador enfatizou ao cliente que estava atuando em uma suspeita de sinistro?', 'Alerta o cliente sobre a gravidade da situação, reforçando a necessidade de atenção e suporte imediato. | Exemplo oficial: "Estamos tratando este caso como uma suspeita de sinistro."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317085, 'TRANSFERENCIA-POSICAO-CLI', 'O operador informou as ações adotadas, resumindo os contatos/tratativas realizados (com ou sem sucesso)?', 'Garante que o cliente tenha visibilidade sobre os esforços da equipe e os próximos passos. | Exemplo oficial: "Já realizamos tentativas de contato com o motorista e ponto de apoio, sem sucesso até o momento."', 1.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317086, 'TRANSFERENCIA-POSICAO-CLI', 'O operador informou corretamente o local onde perdeu a posição? (Estado, cidade, parado/movimento, referência como posto, mecânica, rodovia)', 'Ajuda o cliente a entender o contexto e avaliar o risco da situação. | Exemplo oficial: "A última posição do veículo foi na cidade [cidade], no estado de [estado], com o veículo parado no posto [nome] na rodovia [rodovia]."', 1.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317087, 'TRANSFERENCIA-POSICAO-CLI', 'O operador questionou se o conjunto possui equipamento de contingência? (Ex.: isca, rastreador secundário, bloqueio remoto)', 'Identifica possíveis alternativas para recuperar a visibilidade do veículo. | Exemplo oficial: "Esse veículo possui algum equipamento de contingência, como segundo rastreador ou isca?"', 1.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317088, 'TRANSFERENCIA-POSICAO-CLI', 'O operador questionou se o cliente tem informações recentes sobre o veículo e o motorista? (Ex.: manutenção, revisão, problemas no rastreador)', 'Permite cruzar informações, pois o motorista pode ter informado o cliente antes da gerenciadora. | Exemplo oficial: "O motorista mencionou recentemente alguma manutenção, revisão ou problemas no rastreador diretamente com vocês?"', 1.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
