INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317101, 'TRANSFERENCIA-PARADA-MOT', 'O operador confirmou o motivo pelo qual o motorista parou em local indevido?', 'Identificar a razão da parada permite avaliar riscos e definir a melhor orientação. | Exemplo oficial: "Você precisou parar por algum motivo específico? Houve alguma falha no veículo?"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317102, 'TRANSFERENCIA-PARADA-MOT', 'O operador confirmou se o motorista recebeu o plano de viagem e instruções de rastreamento?', 'Garantir que o motorista esteja ciente das regras e que tenha em mãos os locais homologados. | Exemplo oficial: "Você recebeu todas as orientações sobre os locais homologados para parada?"', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317103, 'TRANSFERENCIA-PARADA-MOT', 'O operador orientou o motorista a reiniciar a viagem e seguir para um local homologado?', 'A saída imediata do local reduz riscos operacionais e de segurança. | Exemplo oficial: "Por favor, retome sua viagem e siga para um local autorizado o mais breve possível."', 1.32, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317104, 'TRANSFERENCIA-PARADA-MOT', 'O operador informou os riscos operacionais da parada indevida, incluindo problemas com seguro?', 'Deixar claro os impactos de uma parada irregular faz com que o motorista compreenda a importância da orientação. | Exemplo oficial: "Essa parada pode comprometer a cobertura do seguro em caso de sinistro. Precisamos que o veículo esteja em um local adequado."', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317105, 'TRANSFERENCIA-PARADA-MOT', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317106, 'TRANSFERENCIA-PARADA-MOT', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317107, 'TRANSFERENCIA-PARADA-MOT', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317108, 'TRANSFERENCIA-PARADA-MOT', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: Exemplo: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317109, 'TRANSFERENCIA-PARADA-MOT', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317110, 'TRANSFERENCIA-PARADA-MOT', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de girias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317111, 'TRANSFERENCIA-PARADA-CLI', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317112, 'TRANSFERENCIA-PARADA-CLI', 'Nome?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317113, 'TRANSFERENCIA-PARADA-CLI', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317114, 'TRANSFERENCIA-PARADA-CLI', 'Confirmou com quem está falando?', 'Garante que a informação seja passada para a pessoa correta. | Exemplo oficial: "Por gentileza, com quem eu falo?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317115, 'TRANSFERENCIA-PARADA-CLI', 'O operador informou claramente o motivo do contato?', 'O cliente precisa entender rapidamente a situação para fornecer informações precisas. | Exemplo oficial: "Estou entrando em contato devido a um alerta parada indevida detectado no sistema. Preciso verificar ua situação."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317116, 'TRANSFERENCIA-PARADA-CLI', 'O operador informou as ações adotadas até o momento?', 'Garante que o cliente tenha clareza sobre as tratativas realizadas e próximos passos. | Exemplo oficial: "Já realizamos tentativas de contato com o motorista e ponto de apoio, sem sucesso até o momento. Estamos acionando as autoridades locais."', 1.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317117, 'TRANSFERENCIA-PARADA-CLI', 'O operador informou corretamente o local da parada? (Cidade, estado, referência como rodovia, posto, mecânica, etc.)', 'Ajuda o cliente a entender o contexto e avaliar o risco da situação. | Exemplo oficial: "O veículo está parado em [cidade], próximo a [posto/mecânica/km da rodovia]."', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317118, 'TRANSFERENCIA-PARADA-CLI', 'O operador confirmou se os pontos de parada autorizada foram passados ao motorista antes do início da viagem?', 'Verifica se o motorista tinha conhecimento prévio das regras de parada. | Exemplo oficial: "O motorista recebeu os pontos de parada autorizada antes do início da viagem? Estava ciente das restrições?"', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317119, 'TRANSFERENCIA-PARADA-CLI', 'O operador informou ao cliente sobre os riscos operacionais e de seguro caso a parada indevida permaneça?', 'Esclarece ao cliente o impacto da parada não autorizada na cobertura do seguro e segurança da carga. | Exemplo oficial: "Caso ocorra um sinistro enquanto o veículo está fora dos pontos autorizados, pode haver impacto na cobertura do seguro da carga e do veículo."', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317120, 'TRANSFERENCIA-PARADA-CLI', 'O operador indicou medidas de segurança ao cliente? (Ex.: Seguir até posto autorizado, acionar escolta, pronta resposta, etc.)', 'Sugere alternativas para mitigar riscos e reforçar a segurança da operação. | Exemplo oficial: "Solicitamos que oriente o motorista a seguir até o posto autorizado mais próximo. Caso a parada persista, poderá ter problemas com a seguradora.', 1.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
