INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317130, 'TRANSFERENCIA-DESVIO-MOT', 'O operador confirmou a senha de segurança antes de prosseguir?', 'A verificação de senha protege a comunicação e evita repasses indevidos de informações. | Exemplo oficial: "Antes de prosseguirmos, poderia me confirmar sua senha de segurança, por favor?"', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317131, 'TRANSFERENCIA-DESVIO-MOT', 'O operador informou claramente o motivo do contato?', 'O motorista precisa entender rapidamente o problema para colaborar com a solução. | Exemplo oficial: "Estamos identificando um desvio de rota no seu trajeto e precisamos entender a situação."', 1.03, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317132, 'TRANSFERENCIA-DESVIO-MOT', 'O operador confirmou o motivo do desvio de rota?', 'Identificar o motivo do desvio é essencial para definir as próximas ações e validar se houve uma alteração planejada. | Exemplo oficial: "O que aconteceu para que você saísse da rota planejada?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317133, 'TRANSFERENCIA-DESVIO-MOT', 'Confirmou se o motorista recebeu o plano de viagem e instruções de rastreamento?', 'Garante que o motorista tinha ciência do trajeto e das regras de monitoramento antes do desvio. | Exemplo oficial: "Você recebeu o plano de viagem com as instruções de rastreamento antes do início da viagem?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317134, 'TRANSFERENCIA-DESVIO-MOT', 'Orientou o motorista a retornar para a rota ou permanecer parado até confirmação com o cliente?', 'Dependendo do motivo do desvio, é necessário orientar a retomada do trajeto ou aguardar autorização. | Exemplo oficial: "Por segurança, oriento que retorne ao trajeto previsto. Caso haja alguma mudança, vamos confirmar com o cliente."', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317135, 'TRANSFERENCIA-DESVIO-MOT', 'Coletou qual itinerário o motorista está realizando?', 'Ajuda a entender se houve uma falha na programação da rota ou se o motorista recebeu uma nova orientação de terceiros. | Exemplo oficial: "Por onde o senhor vai seguir agora? Esse trajeto foi repassado por alguém?"', 1.05, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317136, 'TRANSFERENCIA-DESVIO-MOT', 'O operador informou os riscos operacionais e de seguro caso o motorista continue fora da rota?', 'Esclarece ao motorista que a saída não autorizada da rota pode impactar na cobertura do seguro em caso de sinistro. | Exemplo oficial: "Caso ocorra um sinistro fora da rota homologada, pode haver problemas com a cobertura do seguro da carga e do veículo."', 1.12, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
