INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317148, 'TRANSFERENCIA-DESVIO-CLI', 'O operador enfatizou ao cliente que estava atuando em uma suspeita de sinistro?', 'Alerta o cliente sobre a gravidade da situação, reforçando a necessidade de atenção e suporte imediato. | Exemplo oficial: "Estamos tratando este caso como uma suspeita de sinistro e intensificando as tratativas para garantir a segurança da carga e do veículo."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317149, 'TRANSFERENCIA-DESVIO-CLI', 'O operador informou as ações adotadas até o momento? (Resumir os contatos/tratativas com ou sem sucesso)', 'Garante que o cliente tenha clareza sobre as tratativas realizadas e próximos passos. | Exemplo oficial: "Já tentamos contato com o motorista e não obtivemos retorno. Também acionamos o ponto de apoio mais próximo e seguimos monitorando a movimentação do veículo."', 1.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317150, 'TRANSFERENCIA-DESVIO-CLI', 'O operador informou o trajeto que o motorista está realizando e o que estava programado na rota?', 'Ajuda o cliente a entender a divergência e avaliar o risco da situação. | Exemplo oficial: "O motorista deveria seguir pela [Rodovia X], mas desviou para a [Rodovia Y] sem comunicação prévia."', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317151, 'TRANSFERENCIA-DESVIO-CLI', 'O operador questionou se o cliente tem conhecimento do motivo do desvio? O motorista informou antecipadamente?', 'Verifica se o cliente recebeu algum aviso do motorista, evitando alarmes desnecessários. | Exemplo oficial: "O motorista entrou em contato com vocês para informar que iria desviar? Há alguma orientação interna sobre essa mudança de rota?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317152, 'TRANSFERENCIA-DESVIO-CLI', 'O operador confirmou se o motorista recebeu o plano de viagem e instruções de rastreamento antes da viagem?', 'Garante que o motorista tinha ciência da rota planejada e das regras de rastreamento. | Exemplo oficial: "O motorista recebeu o plano de viagem com a rota definida e as instruções de rastreamento antes da viagem?"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317153, 'TRANSFERENCIA-DESVIO-CLI', 'O operador indicou medidas de segurança ao cliente? (Ex.: Retornar a rota correta ou realizar o ajuste no sistema)', 'Sugere alternativas para mitigar riscos e reforçar a segurança da operação. | Exemplo oficial: "Solicitamos que oriente o motorista a seguir pela rota correta ou que seja feita a alteração via SIL."', 1.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317154, 'TRANSFERENCIA-DESVIO-CLI', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317155, 'TRANSFERENCIA-DESVIO-CLI', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317156, 'TRANSFERENCIA-DESVIO-CLI', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317157, 'TRANSFERENCIA-DESVIO-CLI', 'O operador registrou corretamente o contato no sistema, incluindo número de telefone, nome do responsável, e resumo da conversa?', 'Garante rastreabilidade e facilita acompanhamentos posteriores. | Exemplo oficial: "Contato registrado: Cliente [Nome], Telefone: (XX) XXXX-XXXX, Responsável: [Nome], Resumo: Cliente informou que...', 0.2, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317158, 'TRANSFERENCIA-DESVIO-CLI', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317159, 'TRANSFERENCIA-DESVIO-CLI', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de girias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317160, 'TRANSFERENCIA-PONTO-APOIO', 'Saudação?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317161, 'TRANSFERENCIA-PONTO-APOIO', 'Nome?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317162, 'TRANSFERENCIA-PONTO-APOIO', 'Setor/Empresa?', 'Fracionamento do critério oficial: O operador se identificou informando saudação, nome, setor e empresa? | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317163, 'TRANSFERENCIA-PONTO-APOIO', 'Confirmou com quem está falando?', 'Garante que a informação seja passada para a pessoa correta. | Exemplo oficial: "Por gentileza, com quem eu falo?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317164, 'TRANSFERENCIA-PONTO-APOIO', 'O operador informou claramente o motivo do contato?', 'O atendente precisa entender rapidamente o objetivo da ligação para colaborar com a solução. | Exemplo oficial: "Estamos monitorando um veículo que deve realizar parada no seu ponto de apoio e gostaríamos de confirmar algumas informações."', 1.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317165, 'TRANSFERENCIA-PONTO-APOIO', 'O operador informou os dados e as características do veículo? (cor, placa, modelo)', 'Garante que a verificação seja feita no veículo correto. | Exemplo oficial: "O veículo que estamos monitorando é um [modelo] de cor [cor], placa [placa]."', 1.95, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317166, 'TRANSFERENCIA-PONTO-APOIO', 'O operador passou detalhes da última posição do veículo? (Referência dentro do posto)', 'Confirma se o veículo realmente está no local indicado pelo sistema. | Exemplo oficial: "O sistema mostra que ele está na área de abastecimento do posto. Pode confirmar essa informação?"', 1.6, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317167, 'TRANSFERENCIA-PONTO-APOIO', 'O operador solicitou que o atendente verificasse se o conjunto (cavalo/carreta) estava no local sem violações?', 'Certifica que não houve irregularidades ou violações durante a parada. | Exemplo oficial: "Pode verificar se o conjunto esta sem nenhuma violação?"', 1.6, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317168, 'TRANSFERENCIA-PONTO-APOIO', 'O operador orientou o atendente a chamar o motorista?', 'Em alguns casos, falar diretamente com o motorista pode acelerar a verificação da situação. | Exemplo oficial: "Poderia solicitar que o motorista venha até o telefone para conversarmos?"', 1.6, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317169, 'TRANSFERENCIA-PONTO-APOIO', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
