INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317191, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'O operador se identificou informando saudação, nome, setor e empresa?', 'A identificação profissionaliza o atendimento e garante clareza sobre quem está ligando. | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317192, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'Confirmou com quem está falando?', 'Assegura que a informação seja repassada para a pessoa correta. | Exemplo oficial: "Estou falando com o motorista [Nome]?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317193, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'Informou o motivo do contato?', 'Garante que o motorista compreenda o motivo do contato. | Exemplo oficial: "Estou entrando em contato pois um veículo perdeu o sinal."', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317194, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'Informou o número da OS, Placa ou AE?', 'Essencial para identificar a entrega específica e evitar erros. | Exemplo oficial: "O número da AE é 12345".', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317195, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'O operador informou que o espelhamento foi retirado da conta da Opentech?', 'Informa ao cliente que o veículo está sem sinal para nós, impedindo o monitoramento da viagem. | Exemplo oficial: "Verifiquei no sistema que essa viagem foi gerada, mas o espelhamento do veículo não foi direcionado para a Opentech, impedindo o monitoramento correto da viagem."', 1.95, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317196, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'Operador solicitou ao cliente para refazer o espelhamento do veículo?', 'Demonstra para o cliente que estamos atentos antes mesmo da viagem ser iniciada. | Exemplo oficial: "Por gentileza, preciso que o espelhamento do veículo seja feito para a Opentech, para que possamos realizar o acompanhamento."', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317197, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'Realizou a despedida padrão com cordialidade?', 'Um encerramento educado mantém a postura profissional do atendimento. | Exemplo oficial: "Obrigado por sua atenção. Tenha um excelente dia!"', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317198, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'Utilizou a função mudo corretamente para evitar ruídos externos?', 'O uso correto do mudo evita interferências e mantém a qualidade da chamada. | Exemplo oficial: "Vou colocar no mudo enquanto verifico as informações. Já volto com você."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317199, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'Evitou silêncios prolongados (mais de 45 segundos sem interação)?', 'O preenchimento do silêncio mantém o contato ativo e evita que o motorista pense que a ligação caiu. | Exemplo oficial: "Estou verificando os dados no sistema. Aguarde um momento enquanto faço a consulta."', 0.15, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317200, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'Após a resolução do alerta, finalizou corretamente a ligação sem reter a linha desnecessariamente (10s)?', 'Encerrar a ligação de forma objetiva evita atrasos no atendimento.', 0.2, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317201, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'O operador realizou a qualificação do atendimento corretamente', 'Garante rastreabilidade e facilita acompanhamentos posteriores.', 0.3, 'boolean', 0.0, NULL, 'manual', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317202, 'LOGISTICA-VIAGEM-SEM-ESPELHAMENTO-CLI', 'O volume de voz, entonação e condução da chamada transmitiram credibilidade e cordialidade, sem excesso de gírias?', 'O tom de voz adequado reforça confiança e profissionalismo, garantindo que o motorista siga as instruções corretamente.', 0.1, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317203, 'LOGISTICA-PERDA-POSICAO-CLI', 'O operador se identificou informando saudação, nome, setor e empresa?', 'A identificação profissionaliza o atendimento e garante clareza sobre quem está ligando. | Exemplo oficial: "Bom dia/Boa tarde/Boa noite, aqui é [Nome], do setor [setor] da Opentech."', 0.3, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317204, 'LOGISTICA-PERDA-POSICAO-CLI', 'Confirmou com quem está falando?', 'Assegura que a informação seja repassada para a pessoa correta. | Exemplo oficial: "Estou falando com o motorista [Nome]?"', 0.4, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317205, 'LOGISTICA-PERDA-POSICAO-CLI', 'Informou o motivo do contato?', 'Garante que o motorista compreenda o motivo do contato. | Exemplo oficial: "Estou entrando em contato pois um veículo perdeu o sinal."', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317206, 'LOGISTICA-PERDA-POSICAO-CLI', 'Informou o número da OS, Placa ou AE?', 'Essencial para identificar a entrega específica e evitar erros. | Exemplo oficial: "O número da AE é 12345".', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317207, 'LOGISTICA-PERDA-POSICAO-CLI', 'O operador informou corretamente o local onde perdeu a posição? (Estado, cidade, parado/movimento, referência como posto, mecânica, rodovia)', 'Ajuda o cliente a entender o contexto e avaliar o risco da situação. | Exemplo oficial: "A última posição do veículo foi na cidade [cidade], no estado de [estado], com o veículo parado no posto [nome] na rodovia [rodovia]."', 2.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317208, 'LOGISTICA-PERDA-POSICAO-CLI', 'O operador informou as ações adotadas até o momento?', 'É essencial repassar o contato feito ou as tentativas de contato realizadas com o condutor. | Exemplo oficial: "Até o momento não consegui contato com o condutor"', 1.0, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
INSERT INTO audit_criteria (id, alert_id, label, description, weight, type, deflator, chave, evaluation_type, referencia, exemplo) VALUES (317209, 'LOGISTICA-PERDA-POSICAO-CLI', 'O operador questionou se o cliente tem informações recentes sobre o veículo e o motorista? (Ex.: manutenção, revisão, problemas no rastreador)', 'Permite cruzar informações, pois o motorista pode ter informado o cliente antes da gerenciadora. | Exemplo oficial: "O motorista mencionou recentemente alguma manutenção, revisão ou problemas no rastreador diretamente com vocês?"', 0.95, 'boolean', 0.0, NULL, 'auto', NULL, NULL);
